def lcs_len(a, b):
    # normalized char sequences
    a = normalize(a)
    b = normalize(b)
    n = len(a); m = len(b)
    dp = [0]*(m+1)
    for i in range(1,n+1):
        prev = 0
        for j in range(1,m+1):
            tmp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev+1
            else:
                if dp[j] < dp[j-1]:
                    dp[j] = dp[j-1]
            prev = tmp
    return dp[m], n, m

